args.sparql:
SELECT (COUNT(?event) AS ?count) WHERE {
  ?player wdt:P641 wd:Q13295 ;
          wdt:P1347 ?event .
  ?event wdt:P31 wd:Q131024 .
  ?event wdt:P585 ?date .
  FILTER (?date >= "2013-01-01T00:00:00Z"^^xsd:dateTime && ?date < "2014-01-01T00:00:00Z"^^xsd:dateTime)
} GROUP BY ?player
ORDER BY DESC(?count)
LIMIT 1 OFFSET 2

